import{_ as t,o as a,c as n,a2 as o}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Claude Code — Benchmarks & Performance","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/claude-code/benchmarks.md","filePath":"research/agents/claude-code/benchmarks.md"}'),i={name:"research/agents/claude-code/benchmarks.md"};function r(s,e,d,l,c,h){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="claude-code-—-benchmarks-performance" tabindex="-1">Claude Code — Benchmarks &amp; Performance <a class="header-anchor" href="#claude-code-—-benchmarks-performance" aria-label="Permalink to &quot;Claude Code — Benchmarks &amp; Performance&quot;">​</a></h1><blockquote><p>Benchmark results for Claude Code across Terminal-Bench, SWE-bench, and model-level evaluations.</p></blockquote><h2 id="terminal-bench-2-0" tabindex="-1">Terminal-Bench 2.0 <a class="header-anchor" href="#terminal-bench-2-0" aria-label="Permalink to &quot;Terminal-Bench 2.0&quot;">​</a></h2><p>Terminal-Bench is a benchmark specifically designed to evaluate terminal-based coding agents. It tests agents on real-world coding tasks performed through the terminal.</p><h3 id="claude-code-rankings" tabindex="-1">Claude Code Rankings <a class="header-anchor" href="#claude-code-rankings" aria-label="Permalink to &quot;Claude Code Rankings&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rank</th><th>Agent + Model</th><th>Score</th><th>Notes</th></tr></thead><tbody><tr><td>#39</td><td>Claude Code (Claude Opus 4.6)</td><td>58.0%</td><td>Best Claude Code configuration</td></tr><tr><td>#48</td><td>Claude Code (Claude Opus 4.5)</td><td>52.1%</td><td>Previous generation Opus</td></tr><tr><td>#69</td><td>Claude Code (Claude Sonnet 4.5)</td><td>40.1%</td><td>Cost-effective configuration</td></tr></tbody></table><h3 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h3><ul><li>Terminal-Bench 2.0 evaluates agents in realistic terminal environments</li><li>Tasks include: code generation, debugging, refactoring, file manipulation, git operations</li><li>Claude Code competes against specialized agents and other general-purpose coding tools</li><li>Rankings are publicly maintained and updated as agents improve</li></ul><h3 id="observations" tabindex="-1">Observations <a class="header-anchor" href="#observations" aria-label="Permalink to &quot;Observations&quot;">​</a></h3><ul><li><strong>Opus 4.6 vs Opus 4.5</strong>: ~6% improvement between model generations, showing direct model quality impact</li><li><strong>Opus vs Sonnet</strong>: ~18% gap between Opus 4.6 and Sonnet 4.5, confirming Opus&#39;s stronger reasoning</li><li><strong>Mid-pack positioning</strong>: Claude Code ranks in the middle tier, not at the top. This suggests the agentic harness quality matters as much as the underlying model</li><li><strong>Model dependence</strong>: Performance is strongly tied to the underlying model, as expected for an agentic system</li></ul><h2 id="swe-bench" tabindex="-1">SWE-bench <a class="header-anchor" href="#swe-bench" aria-label="Permalink to &quot;SWE-bench&quot;">​</a></h2><p>SWE-bench evaluates AI systems on real software engineering tasks derived from GitHub issues and pull requests.</p><h3 id="known-results" tabindex="-1">Known Results <a class="header-anchor" href="#known-results" aria-label="Permalink to &quot;Known Results&quot;">​</a></h3><p>Anthropic has published SWE-bench results for Claude models (used by various agents including Claude Code):</p><table tabindex="0"><thead><tr><th>Benchmark</th><th>Model</th><th>Score</th><th>Date</th></tr></thead><tbody><tr><td>SWE-bench Verified</td><td>Claude Sonnet 4</td><td>72.7%</td><td>Jun 2025</td></tr><tr><td>SWE-bench Verified</td><td>Claude Opus 4</td><td>72.5%</td><td>Jun 2025</td></tr><tr><td>SWE-bench Verified</td><td>Claude Sonnet 3.5 (v2)</td><td>49.0%</td><td>Oct 2024</td></tr><tr><td>SWE-bench Verified</td><td>Claude Sonnet 3.5</td><td>33.4%</td><td>Jun 2024</td></tr></tbody></table><p><strong>Important caveat</strong>: These are model-level scores using Anthropic&#39;s internal scaffolding, not necessarily Claude Code specifically. Different agentic harnesses (Claude Code vs. Devin vs. SWE-Agent) can produce different scores with the same underlying model.</p><h3 id="swe-bench-context" tabindex="-1">SWE-bench Context <a class="header-anchor" href="#swe-bench-context" aria-label="Permalink to &quot;SWE-bench Context&quot;">​</a></h3><ul><li>SWE-bench Verified is a curated subset of 500 tasks from the full SWE-bench dataset</li><li>Tasks involve fixing real GitHub issues: understanding the issue, locating relevant code, implementing a fix, and passing tests</li><li>The benchmark tests both reasoning (understanding the bug) and execution (making the right edit)</li><li>Claude Code&#39;s performance on SWE-bench is likely close to the model scores above, given its full toolset</li></ul><h2 id="model-level-performance-characteristics" tabindex="-1">Model-Level Performance Characteristics <a class="header-anchor" href="#model-level-performance-characteristics" aria-label="Permalink to &quot;Model-Level Performance Characteristics&quot;">​</a></h2><p>From Anthropic&#39;s documentation and observable behavior, different models show different strengths:</p><h3 id="claude-opus-4-6-4-5" tabindex="-1">Claude Opus 4.6 / 4.5 <a class="header-anchor" href="#claude-opus-4-6-4-5" aria-label="Permalink to &quot;Claude Opus 4.6 / 4.5&quot;">​</a></h3><ul><li><strong>Strongest reasoning</strong>: Best for complex architectural decisions, difficult bugs</li><li><strong>Adaptive reasoning</strong>: Dynamically allocates thinking tokens based on effort level</li><li><strong>Extended thinking</strong>: Deeper analysis before responding</li><li><strong>Cost</strong>: Most expensive per token</li><li><strong>Speed</strong>: Slowest of the three tiers</li><li><strong>Best for</strong>: Complex refactors, architecture design, difficult debugging</li></ul><h3 id="claude-sonnet-4-6-4-5-4" tabindex="-1">Claude Sonnet 4.6 / 4.5 / 4 <a class="header-anchor" href="#claude-sonnet-4-6-4-5-4" aria-label="Permalink to &quot;Claude Sonnet 4.6 / 4.5 / 4&quot;">​</a></h3><ul><li><strong>Balanced performance</strong>: Good reasoning at moderate cost</li><li><strong>Daily driver</strong>: Recommended for most coding tasks</li><li><strong>Adaptive reasoning</strong>: Same as Opus on 4.6</li><li><strong>Cost</strong>: Mid-tier</li><li><strong>Speed</strong>: Moderate</li><li><strong>Best for</strong>: Feature implementation, routine debugging, code review</li></ul><h3 id="claude-haiku" tabindex="-1">Claude Haiku <a class="header-anchor" href="#claude-haiku" aria-label="Permalink to &quot;Claude Haiku&quot;">​</a></h3><ul><li><strong>Fastest</strong>: Lowest latency, cheapest</li><li><strong>Used by</strong>: Explore sub-agent (built-in), Claude Code Guide sub-agent</li><li><strong>Trade-off</strong>: Less reasoning depth, more suitable for search/lookup tasks</li><li><strong>Best for</strong>: Codebase exploration, quick lookups, sub-agent tasks</li></ul><h2 id="effort-level-impact" tabindex="-1">Effort Level Impact <a class="header-anchor" href="#effort-level-impact" aria-label="Permalink to &quot;Effort Level Impact&quot;">​</a></h2><p>Claude Code supports effort levels (<code>/effort low|medium|high</code>) on Opus 4.6 and Sonnet 4.6:</p><table tabindex="0"><thead><tr><th>Effort Level</th><th>Behavior</th><th>Use Case</th></tr></thead><tbody><tr><td><code>low</code></td><td>Minimal thinking, fast responses</td><td>Simple questions, quick edits</td></tr><tr><td><code>medium</code></td><td>Balanced thinking (default)</td><td>Standard coding tasks</td></tr><tr><td><code>high</code></td><td>Deep reasoning, more thinking tokens</td><td>Complex architecture, hard bugs</td></tr></tbody></table><p>The <code>ultrathink</code> keyword in a prompt sets effort to high for that turn only.</p><h2 id="context-window-as-performance-factor" tabindex="-1">Context Window as Performance Factor <a class="header-anchor" href="#context-window-as-performance-factor" aria-label="Permalink to &quot;Context Window as Performance Factor&quot;">​</a></h2><p>From Anthropic&#39;s best practices, context window usage directly impacts quality:</p><ul><li><strong>Fresh context</strong>: Highest quality responses, instructions followed precisely</li><li><strong>50-70% full</strong>: Good quality, may start losing early instructions</li><li><strong>Near capacity</strong>: Quality degrades, earlier instructions may be forgotten</li><li><strong>Auto-compaction triggered</strong>: Quality reset after compaction, but nuance may be lost</li></ul><p>This is why the docs recommend:</p><ul><li><code>/clear</code> between unrelated tasks</li><li>Sub-agents for exploration (separate context)</li><li>CLAUDE.md for persistent instructions (survives compaction)</li><li>Skills for on-demand knowledge (not loaded until needed)</li></ul><h2 id="comparative-positioning" tabindex="-1">Comparative Positioning <a class="header-anchor" href="#comparative-positioning" aria-label="Permalink to &quot;Comparative Positioning&quot;">​</a></h2><h3 id="vs-other-cli-agents" tabindex="-1">vs. Other CLI Agents <a class="header-anchor" href="#vs-other-cli-agents" aria-label="Permalink to &quot;vs. Other CLI Agents&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Approach</th><th>Relative Strength</th></tr></thead><tbody><tr><td><strong>Claude Code</strong></td><td>First-party Anthropic agent, deep Claude integration</td><td>Permission model, context management, multi-surface</td></tr><tr><td><strong>GitHub Copilot CLI</strong></td><td>GitHub/Microsoft agent for terminal</td><td>GitHub integration, broad model support</td></tr><tr><td><strong>Aider</strong></td><td>Open-source Python CLI agent</td><td>Model-agnostic, git-centric, transparent</td></tr><tr><td><strong>Cline</strong></td><td>VS Code extension (formerly Claude Dev)</td><td>IDE integration, model-agnostic</td></tr></tbody></table><h3 id="vs-ide-agents" tabindex="-1">vs. IDE Agents <a class="header-anchor" href="#vs-ide-agents" aria-label="Permalink to &quot;vs. IDE Agents&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Approach</th><th>Relative Strength</th></tr></thead><tbody><tr><td><strong>Cursor</strong></td><td>Full IDE (Electron) with agent mode</td><td>Tight IDE integration, inline editing</td></tr><tr><td><strong>Windsurf</strong></td><td>IDE with Cascade agent</td><td>Flow-based editing, inline experience</td></tr><tr><td><strong>Claude Code (VS Code)</strong></td><td>Extension in existing IDE</td><td>Uses the full Claude Code engine inside VS Code</td></tr></tbody></table><h3 id="key-competitive-observations" tabindex="-1">Key Competitive Observations <a class="header-anchor" href="#key-competitive-observations" aria-label="Permalink to &quot;Key Competitive Observations&quot;">​</a></h3><ol><li><p><strong>Model lock-in vs. model advantage</strong>: Claude Code only works with Claude models, but has the deepest integration with them (adaptive reasoning, effort levels, extended thinking). Competitors offer model flexibility.</p></li><li><p><strong>Terminal-first vs. IDE-first</strong>: Claude Code is architecturally terminal-first (IDE support is via extensions). Cursor and Windsurf are IDE-first. This shapes the user experience and workflow differently.</p></li><li><p><strong>Open vs. closed</strong>: Aider is fully open-source. Claude Code is closed-source with a public npm package and plugin system. This affects community contribution and transparency.</p></li><li><p><strong>Permission sophistication</strong>: Claude Code&#39;s 5-mode permission system with glob patterns, scoped settings, hooks, and sandboxing is the most sophisticated in the space. Most competitors have simpler models.</p></li></ol><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><p>Based on documentation and observable behavior:</p><ol><li><strong>Claude-only</strong>: Cannot use non-Anthropic models (GPT-4, Gemini, Llama, etc.)</li><li><strong>Context window ceiling</strong>: Like all LLM agents, limited by context window size; long sessions degrade quality</li><li><strong>Cost</strong>: Usage-based pricing; Opus sessions can be expensive for long tasks</li><li><strong>Closed-source core</strong>: The agentic harness is not open-source; community cannot inspect or contribute to core</li><li><strong>Terminal-centric</strong>: While IDE extensions exist, the core experience is terminal-based, which may not suit all developers</li><li><strong>LSP via plugins only</strong>: Type checking and code intelligence require separate plugin installation</li></ol>',45)])])}const p=t(i,[["render",r]]);export{g as __pageData,p as default};
